/**
 * ActivityFeed Component
 *
 * A timeline of events and activities for SaaS dashboards.
 * Optimized for Product Mode with efficient scanning and clear hierarchy.
 *
 * @example
 * ```tsx
 * <ActivityFeed
 *   activities={[
 *     {
 *       id: '1',
 *       type: 'comment',
 *       actor: { name: 'John Doe' },
 *       title: 'Commented on Project X',
 *       relativeTime: '2 hours ago'
 *     }
 *   ]}
 * />
 * ```
 */

import { forwardRef } from 'react';
import {
  MessageSquare,
  Edit,
  Plus,
  Trash2,
  UserPlus,
  CheckCircle,
  Upload,
  Circle,
} from 'lucide-react';
import type { ActivityFeedProps, ActivityItem } from './ActivityFeed.types';
import styles from './ActivityFeed.module.css';

// Type to icon mapping
const typeIcons: Record<string, React.ReactNode> = {
  comment: <MessageSquare size={16} />,
  update: <Edit size={16} />,
  create: <Plus size={16} />,
  delete: <Trash2 size={16} />,
  assign: <UserPlus size={16} />,
  complete: <CheckCircle size={16} />,
  upload: <Upload size={16} />,
  default: <Circle size={16} />,
};

// Activity item component
const ActivityItemComponent = ({
  item,
  showConnector,
  compact,
}: {
  item: ActivityItem;
  showConnector: boolean;
  compact: boolean;
}) => {
  const icon = item.icon || typeIcons[item.type || 'default'];
  const iconVariant = item.iconVariant || 'default';

  return (
    <div className={`${styles.item} ${compact ? styles.itemCompact : ''}`}>
      <div className={styles.iconColumn}>
        <div className={`${styles.iconWrapper} ${styles[`iconVariant-${iconVariant}`]}`}>
          {icon}
        </div>
        {showConnector && <div className={styles.connector} />}
      </div>

      <div className={styles.content}>
        <div className={styles.header}>
          {item.actor && (
            <span className={styles.actor}>
              {item.actor.avatar && (
                <img
                  src={item.actor.avatar}
                  alt={item.actor.name}
                  className={styles.avatar}
                />
              )}
              {item.actor.href ? (
                <a href={item.actor.href} className={styles.actorName}>
                  {item.actor.name}
                </a>
              ) : (
                <span className={styles.actorName}>{item.actor.name}</span>
              )}
            </span>
          )}
          <span className={styles.title}>{item.title}</span>
          <span className={styles.time}>{item.relativeTime || item.timestamp}</span>
        </div>

        {item.description && (
          <div className={styles.description}>{item.description}</div>
        )}

        {item.metadata && Object.keys(item.metadata).length > 0 && (
          <div className={styles.metadata}>
            {Object.entries(item.metadata).map(([key, value]) => (
              <span key={key} className={styles.metadataItem}>
                <span className={styles.metadataKey}>{key}:</span>
                <span className={styles.metadataValue}>{value}</span>
              </span>
            ))}
          </div>
        )}

        {item.actions && <div className={styles.actions}>{item.actions}</div>}
      </div>
    </div>
  );
};

export const ActivityFeed = forwardRef<HTMLDivElement, ActivityFeedProps>(
  (
    {
      activities,
      showFilters = false,
      filters,
      activeFilter,
      onFilterChange,
      onLoadMore,
      hasMore = false,
      loading = false,
      emptyMessage = 'No activity yet.',
      showConnectors = true,
      compact = false,
      className,
      ...rest
    },
    ref
  ) => {
    const classNames = [
      styles.activityFeed,
      compact && styles.compact,
      className,
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Filters */}
        {showFilters && filters && filters.length > 0 && (
          <div className={styles.filters}>
            {filters.map((filter) => (
              <button
                key={filter.value}
                type="button"
                className={`${styles.filterButton} ${activeFilter === filter.value ? styles.filterActive : ''}`}
                onClick={() => onFilterChange?.(filter.value)}
              >
                {filter.label}
                {filter.count !== undefined && (
                  <span className={styles.filterCount}>{filter.count}</span>
                )}
              </button>
            ))}
          </div>
        )}

        {/* Activity list */}
        <div className={styles.list}>
          {activities.length === 0 && !loading ? (
            <div className={styles.empty}>{emptyMessage}</div>
          ) : (
            activities.map((activity, index) => (
              <ActivityItemComponent
                key={activity.id}
                item={activity}
                showConnector={showConnectors && index < activities.length - 1}
                compact={compact}
              />
            ))
          )}

          {/* Loading skeleton */}
          {loading && (
            <>
              {[1, 2, 3].map((i) => (
                <div key={i} className={styles.skeleton}>
                  <div className={styles.skeletonIcon} />
                  <div className={styles.skeletonContent}>
                    <div className={styles.skeletonTitle} />
                    <div className={styles.skeletonDesc} />
                  </div>
                </div>
              ))}
            </>
          )}
        </div>

        {/* Load more */}
        {hasMore && !loading && (
          <button
            type="button"
            className={styles.loadMore}
            onClick={onLoadMore}
          >
            Load more
          </button>
        )}
      </div>
    );
  }
);

ActivityFeed.displayName = 'ActivityFeed';

/**
 * ActivityFeed Component Types
 *
 * Type definitions for the Orion ActivityFeed section component.
 * A timeline of events and activities for SaaS dashboards.
 */

import type { HTMLAttributes, ReactNode } from 'react';

/**
 * Activity item actor (who performed the action)
 */
export interface ActivityActor {
  /**
   * Actor name
   */
  name: string;

  /**
   * Avatar URL
   */
  avatar?: string;

  /**
   * Link to actor profile
   */
  href?: string;
}

/**
 * Activity item for the feed
 */
export interface ActivityItem {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Activity type for icon selection
   */
  type?: 'comment' | 'update' | 'create' | 'delete' | 'assign' | 'complete' | 'upload' | 'default';

  /**
   * Custom icon (overrides type-based icon)
   */
  icon?: ReactNode;

  /**
   * Icon background color variant
   */
  iconVariant?: 'default' | 'success' | 'warning' | 'error' | 'info' | 'brand';

  /**
   * Actor who performed the action
   */
  actor?: ActivityActor;

  /**
   * Activity title/summary
   */
  title: ReactNode;

  /**
   * Activity description/content
   */
  description?: ReactNode;

  /**
   * Timestamp
   */
  timestamp: string;

  /**
   * Relative time (e.g., "2 hours ago")
   */
  relativeTime?: string;

  /**
   * Associated metadata
   */
  metadata?: Record<string, ReactNode>;

  /**
   * Action buttons
   */
  actions?: ReactNode;
}

/**
 * ActivityFeed filter option
 */
export interface ActivityFilter {
  /**
   * Filter value
   */
  value: string;

  /**
   * Filter label
   */
  label: string;

  /**
   * Item count for this filter
   */
  count?: number;
}

/**
 * ActivityFeed section props
 *
 * @example
 * ```tsx
 * <ActivityFeed
 *   activities={[
 *     {
 *       id: '1',
 *       type: 'comment',
 *       actor: { name: 'John Doe', avatar: '/avatars/john.jpg' },
 *       title: 'Commented on Project X',
 *       description: 'Great progress on the design!',
 *       timestamp: '2024-01-15T10:30:00Z',
 *       relativeTime: '2 hours ago'
 *     }
 *   ]}
 * />
 * ```
 */
export interface ActivityFeedProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Array of activity items
   */
  activities: ActivityItem[];

  /**
   * Show filter controls
   * @default false
   */
  showFilters?: boolean;

  /**
   * Filter options
   */
  filters?: ActivityFilter[];

  /**
   * Current filter value
   */
  activeFilter?: string;

  /**
   * Filter change handler
   */
  onFilterChange?: (filter: string) => void;

  /**
   * Load more callback
   */
  onLoadMore?: () => void;

  /**
   * Whether more items are available
   */
  hasMore?: boolean;

  /**
   * Loading state
   */
  loading?: boolean;

  /**
   * Empty state message
   */
  emptyMessage?: string;

  /**
   * Show connector lines between items
   * @default true
   */
  showConnectors?: boolean;

  /**
   * Compact mode
   * @default false
   */
  compact?: boolean;
}

/**
 * ActivityFeed Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Timeline layout with efficient information scanning.
 */

.activityFeed {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-4);
}

/* ============================================================================
 * FILTERS
 * ============================================================================ */

.filters {
  display: flex;
  gap: var(--spacing-2);
  flex-wrap: wrap;
  padding-bottom: var(--spacing-4);
  border-bottom: 1px solid var(--border-subtle);
}

.filterButton {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
  padding: var(--spacing-1-5) var(--spacing-3);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  background: var(--surface-subtle);
  border: 1px solid transparent;
  border-radius: var(--radius-full);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.filterButton:hover {
  color: var(--text-primary);
  background: var(--surface-layer);
}

.filterActive {
  color: var(--interactive-primary);
  background: var(--status-info-bg);
  border-color: var(--interactive-primary);
}

.filterCount {
  font-size: var(--font-size-11);
  background: var(--surface-base);
  padding: var(--spacing-0-5) var(--spacing-1-5);
  border-radius: var(--radius-full);
}

.filterActive .filterCount {
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

/* ============================================================================
 * LIST
 * ============================================================================ */

.list {
  display: flex;
  flex-direction: column;
}

.empty {
  padding: var(--spacing-8);
  text-align: center;
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  color: var(--text-tertiary);
}

/* ============================================================================
 * ITEM
 * ============================================================================ */

.item {
  display: flex;
  gap: var(--spacing-3);
  padding: var(--spacing-3) 0;
}

.itemCompact {
  padding: var(--spacing-2) 0;
}

/* Icon column */
.iconColumn {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
}

.iconWrapper {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-full);
  background: var(--surface-subtle);
  color: var(--text-secondary);
  flex-shrink: 0;
}

.iconVariant-success {
  background: var(--status-success-bg);
  color: var(--text-success);
}

.iconVariant-warning {
  background: var(--status-warning-bg);
  color: var(--text-warning);
}

.iconVariant-error {
  background: var(--status-error-bg);
  color: var(--text-error);
}

.iconVariant-info {
  background: var(--status-info-bg);
  color: var(--text-info);
}

.iconVariant-brand {
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

.connector {
  width: 2px;
  flex: 1;
  min-height: 16px;
  background: var(--border-subtle);
  margin-top: var(--spacing-2);
}

/* Content */
.content {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-1);
}

.header {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  line-height: var(--line-height-relaxed);
}

.actor {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
}

.avatar {
  width: 20px;
  height: 20px;
  border-radius: var(--radius-full);
  object-fit: cover;
}

.actorName {
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
  text-decoration: none;
}

a.actorName:hover {
  text-decoration: underline;
}

.title {
  color: var(--text-primary);
}

.time {
  color: var(--text-tertiary);
  font-size: var(--font-size-12);
  margin-left: auto;
  flex-shrink: 0;
}

.description {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-secondary);
  line-height: var(--line-height-relaxed);
  padding: var(--spacing-2) var(--spacing-3);
  background: var(--surface-subtle);
  border-radius: var(--radius-sm);
  margin-top: var(--spacing-1);
}

.metadata {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-3);
  margin-top: var(--spacing-1);
}

.metadataItem {
  display: inline-flex;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
}

.metadataKey {
  color: var(--text-tertiary);
}

.metadataValue {
  color: var(--text-secondary);
}

.actions {
  display: flex;
  gap: var(--spacing-2);
  margin-top: var(--spacing-2);
}

/* ============================================================================
 * COMPACT MODE
 * ============================================================================ */

.compact .iconWrapper {
  width: 24px;
  height: 24px;
}

.compact .header {
  font-size: var(--font-size-13);
}

.compact .description {
  font-size: var(--font-size-12);
  padding: var(--spacing-1-5) var(--spacing-2);
}

/* ============================================================================
 * LOADING SKELETON
 * ============================================================================ */

.skeleton {
  display: flex;
  gap: var(--spacing-3);
  padding: var(--spacing-3) 0;
}

.skeletonIcon {
  width: 32px;
  height: 32px;
  border-radius: var(--radius-full);
  background: var(--surface-subtle);
  animation: pulse 1.5s ease-in-out infinite;
}

.skeletonContent {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.skeletonTitle {
  width: 60%;
  height: 16px;
  border-radius: var(--radius-sm);
  background: var(--surface-subtle);
  animation: pulse 1.5s ease-in-out infinite;
}

.skeletonDesc {
  width: 80%;
  height: 12px;
  border-radius: var(--radius-sm);
  background: var(--surface-subtle);
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

/* ============================================================================
 * LOAD MORE
 * ============================================================================ */

.loadMore {
  width: 100%;
  padding: var(--spacing-3);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
  background: var(--surface-subtle);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
  margin-top: var(--spacing-2);
}

.loadMore:hover {
  color: var(--text-primary);
  background: var(--surface-layer);
}
